+            vec![
+                Scalar::Float64(1.0),
+                Scalar::Null(NullKind::NaN),
+                Scalar::Float64(3.0),
+            ],
+        )
+        .unwrap();
+
+        let default_interp = s.interpolate().unwrap();
+        let linear_interp = s.interpolate_method("linear").unwrap();
+        assert_eq!(default_interp.values(), linear_interp.values());
